import React, { useState } from "react";

export default function WithdrawGoalScreen({ goal, onBack, onUpdateGoal }) {
  const [amount, setAmount] = useState("");

  const handleWithdraw = () => {
    const num = Number(amount);
    if (num <= 0 || num > goal.current) return;

    const updatedGoal = { ...goal, current: goal.current - num };
    onUpdateGoal(updatedGoal);
    onBack(); // go back to GoalDetailsScreen
  };

  return (
    <div className="p-6 min-h-screen flex flex-col">
      <button onClick={onBack} className="mb-6 text-gray-500">
        ← Back
      </button>

      <h2 className="text-2xl font-bold mb-4">Withdraw from {goal.title}</h2>

      <input
        type="number"
        placeholder="Amount"
        value={amount}
        onChange={(e) => setAmount(e.target.value)}
        className="mb-4 p-3 rounded-xl border border-gray-300"
      />

      <button
        onClick={handleWithdraw}
        className="mt-auto py-3 bg-red-500 text-white rounded-xl font-bold"
      >
        Withdraw
      </button>
    </div>
  );
}
